import React, { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";

// --- Importa tu logo aquí ---
import logo from '../assets/logo.png';

// --- AJUSTABLES ---
const USER_ICON_ACTUAL_SIZE = "100px";
const TITLE_FONT_SIZE = "40px";
const SMALL_ICON_SVG_SIZE = "26px";
const LABEL_FONT_SIZE = "19px";
const INPUT_FONT_SIZE = "20px";
const BUTTON_FONT_SIZE = "24px";
const MESSAGE_FONT_SIZE = "18px";
const MODAL_WIDTH = "530px";
const MODAL_PADDING_VERTICAL = "40px";
const MODAL_PADDING_HORIZONTAL = "40px";
const CLOSE_BUTTON_FONT_SIZE = "40px";

// Componente del ícono de ojo (mostrar contraseña)
const EyeIconShow = ({ color, size = SMALL_ICON_SVG_SIZE }) => (
  <svg
    viewBox="0 0 24 24"
    width={size}
    height={size}
    fill="none"
    stroke={color}
    strokeWidth="2"
    strokeLinecap="round"
    strokeLinejoin="round"
  >
    <path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z" />
    <circle cx="12" cy="12" r="3" />
  </svg>
);

// Componente del ícono de ojo (ocultar contraseña)
const EyeIconHide = ({ color, size = SMALL_ICON_SVG_SIZE }) => (
  <svg
    viewBox="0 0 24 24"
    width={size}
    height={size}
    fill="none"
    stroke={color}
    strokeWidth="2"
    strokeLinecap="round"
    strokeLinejoin="round"
  >
    <path d="M17.94 17.94A10.07 10.07 0 0 1 12 20c-7 0-11-8-11-8a18.45 18.45 0 0 1 5.06-5.94M9.9 4.24A9.12 9.12 0 0 1 12 4c7 0 11 8 11 8a18.5 18.5 0 0 1-2.16 3.19m-6.72-1.07a3 3 0 1 1-4.24-4.24" />
    <line x1="1" y1="1" x2="23" y2="23" />
  </svg>
);

const InicioSesion = ({ onLogin, onClose }) => {
  const [usuario, setUsuario] = useState("");
  const [contrasenia, setContrasenia] = useState("");
  const [showPassword, setShowPassword] = useState(false);
  const [mensaje, setMensaje] = useState("");
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setMensaje("");

    try {
      const response = await fetch("http://localhost:3001/api/usuarios/login", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          usuario: usuario,
          contrasenia: contrasenia,
        }),
      });

      const data = await response.json();

      if (response.ok) {
        setMensaje("¡Sesión iniciada correctamente!");
        setTimeout(() => {
          onLogin(data);
        }, 1000);
      } else {
        setMensaje(data.mensaje || "Error al iniciar sesión");
      }
    } catch (error) {
      setMensaje("Error de conexión. Inténtalo de nuevo.");
    } finally {
      setLoading(false);
    }
  };

  const handleClose = () => {
    setMensaje("");
    setUsuario("");
    setContrasenia("");
    onClose();
  };

  // Variantes de animación para framer-motion
  const modalVariants = {
    hidden: { opacity: 0, scale: 0.8, y: -50 },
    visible: { 
      opacity: 1, 
      scale: 1, 
      y: 0,
      transition: { 
        type: "spring", 
        duration: 0.5,
        bounce: 0.3
      }
    },
    exit: { 
      opacity: 0, 
      scale: 0.8, 
      y: -50,
      transition: { duration: 0.3 }
    }
  };

  const iconVariants = {
    hidden: { scale: 0, rotate: -180 },
    visible: { 
      scale: 1, 
      rotate: 0,
      transition: { 
        type: "spring", 
        duration: 0.6,
        delay: 0.2
      }
    },
    exit: { scale: 0, rotate: 180 }
  };

  const inputVariants = {
    focus: { 
      scale: 1.02,
      boxShadow: "0 0 0 3px rgba(242, 158, 56, 0.2)"
    }
  };

  const buttonVariants = {
    hover: { 
      scale: 1.05,
      boxShadow: "0 8px 25px rgba(242, 158, 56, 0.3)"
    },
    tap: { scale: 0.95 }
  };

  return (
    <AnimatePresence>
      {onClose && (
        <motion.div
          className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50"
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          exit={{ opacity: 0 }}
          onClick={handleClose}
        >
          <motion.div
            className="bg-background rounded-2xl w-[530px] p-10 text-center font-bodoni shadow-2xl border-2 border-black relative"
            variants={modalVariants}
            initial="hidden"
            animate="visible"
            exit="exit"
            onClick={(e) => e.stopPropagation()}
          >
            {/* Botón de cerrar */}
            <motion.button
              onClick={handleClose}
              className="absolute top-4 right-5 bg-transparent border-none text-4xl cursor-pointer text-text-muted leading-none p-1 outline-none transition-all duration-200 hover:text-red-500 hover:scale-110"
              whileHover={{ scale: 1.2 }}
              whileTap={{ scale: 0.9 }}
            >
              &times;
            </motion.button>

            {/* Logo centrado */}
            <motion.div 
              className="flex justify-center mb-8"
              variants={iconVariants}
              initial="hidden"
              animate="visible"
              exit="exit"
            >
              <img 
                src={logo}
                alt="Logo de la aplicación"
                className="w-24 h-24 object-contain select-none"
              />
            </motion.div>

            {/* Título */}
            <h2 className="text-4xl font-bold text-text-main mb-11 uppercase tracking-widest font-bodoni">
              Inicio de Sesión
            </h2>

            {/* Mensaje de éxito/error */}
            {mensaje && (
              <motion.p 
                className={`mb-8 font-bold text-lg min-h-8 font-bodoni ${
                  mensaje === "¡Sesión iniciada correctamente!" 
                    ? "text-green-600" 
                    : "text-red-500"
                }`}
                initial={{ opacity: 0, y: -10 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ duration: 0.3 }}
              >
                {mensaje}
              </motion.p>
            )}

            {/* Formulario */}
            <form onSubmit={handleSubmit} className="text-left space-y-6">
              {/* Campo de Usuario */}
              <div>
                <label 
                  htmlFor="usuario" 
                  className="block text-text-main text-lg font-medium mb-2 font-bodoni"
                >
                  Usuario
                </label>
                <motion.input
                  type="text"
                  id="usuario"
                  placeholder="Escribe tu usuario"
                  value={usuario}
                  onChange={(e) => setUsuario(e.target.value)}
                  className="w-full px-4 py-3 border border-stroke rounded-lg text-lg font-miles bg-white bg-opacity-60 focus:outline-none focus:ring-2 focus:ring-accent focus:border-accent transition-all duration-200"
                  variants={inputVariants}
                  whileFocus="focus"
                  required
                />
              </div>

              {/* Campo de Contraseña */}
              <div>
                <label 
                  htmlFor="contrasenia" 
                  className="block text-text-main text-lg font-medium mb-2 font-bodoni"
                >
                  Contraseña
                </label>
                <div className="relative">
                  <motion.input
                    type={showPassword ? "text" : "password"}
                    id="contrasenia"
                    placeholder="Introduce tu contraseña"
                    value={contrasenia}
                    onChange={(e) => setContrasenia(e.target.value)}
                    className="w-full px-4 py-3 pr-12 border border-stroke rounded-lg text-lg font-miles bg-white bg-opacity-60 focus:outline-none focus:ring-2 focus:ring-accent focus:border-accent transition-all duration-200"
                    variants={inputVariants}
                    whileFocus="focus"
                    required
                  />
                  <motion.button
                    type="button"
                    onClick={() => setShowPassword(!showPassword)}
                    className="absolute top-1/2 right-3 transform -translate-y-1/2 bg-transparent border-none cursor-pointer p-0 flex items-center justify-center text-text-muted leading-none hover:text-primary transition-colors duration-200"
                    whileHover={{ opacity: 0.7, scale: 1.1 }}
                    whileTap={{ scale: 0.9 }}
                    title={showPassword ? "Ocultar contraseña" : "Mostrar contraseña"}
                  >
                    {showPassword ? (
                      <EyeIconHide color="currentColor" size={SMALL_ICON_SVG_SIZE} />
                    ) : (
                      <EyeIconShow color="currentColor" size={SMALL_ICON_SVG_SIZE} />
                    )}
                  </motion.button>
                </div>
              </div>

              {/* Botón de Enviar */}
              <motion.button
                type="submit"
                disabled={loading}
                className="w-full bg-accent text-primary px-6 py-3 rounded-lg text-2xl font-bold font-bodoni cursor-pointer transition-all duration-200 hover:bg-opacity-80 disabled:opacity-50 disabled:cursor-not-allowed"
                variants={buttonVariants}
                whileHover="hover"
                whileTap="tap"
              >
                {loading ? "Accediendo..." : "ACCEDER"}
              </motion.button>
            </form>
          </motion.div>
        </motion.div>
      )}
    </AnimatePresence>
  );
};

export default InicioSesion;
